// app/dashboard/alerts/page.tsx - Updated
'use client'

import { useState } from 'react'
import { Header } from '../../../components/layout/Header'
import { toast } from 'react-hot-toast'
import { 
  FiAlertCircle, 
  FiCheckCircle, 
  FiClock, 
  FiFilter,
  FiRefreshCw,
  FiBell,
  FiUserCheck,
  FiNavigation
} from 'react-icons/fi'
import { useAlerts } from '../../../hooks/useAlerts'
import { Loader } from '../../../components/common/Loader'

export default function AlertsPage() {
  const { alerts, loading, error, markAsRead, deleteAlert, refresh } = useAlerts()
  const [filter, setFilter] = useState('all')

  const filteredAlerts = alerts.filter(alert => {
    if (filter === 'unread') return !alert.read
    if (filter === 'read') return alert.read
    if (filter !== 'all') return alert.type === filter
    return true
  })

  const getSeverityColor = (severity: string) => {
    switch (severity) {
      case 'error': return 'bg-error/10 text-error border-error/20'
      case 'warning': return 'bg-yellow-100 text-yellow-800 border-yellow-200'
      case 'info': 
      default: return 'bg-blue-100 text-blue-800 border-blue-200'
    }
  }

  const getTypeIcon = (type: string) => {
    switch (type) {
      case 'new_route': return <FiNavigation className="mr-2" />
      case 'payment': return <FiBell className="mr-2" />
      case 'user': return <FiUserCheck className="mr-2" />
      case 'system': return <FiAlertCircle className="mr-2" />
      default: return <FiAlertCircle className="mr-2" />
    }
  }

  const handleCheckNewRoutes = async () => {
    try {
      // This would check for new routes and create alerts
      toast.success('Checked for new routes')
      refresh()
    } catch (error) {
      toast.error('Failed to check for new routes')
    }
  }

  if (loading) {
    return (
      <div className="space-y-6">
        <Header title="Alerts & Monitoring" />
        <Loader message="Loading alerts..." />
      </div>
    )
  }

  if (error) {
    return (
      <div className="space-y-6">
        <Header title="Alerts & Monitoring" />
        <div className="bg-white p-6 rounded-lg shadow">
          <div className="text-center py-12">
            <FiAlertCircle className="mx-auto text-4xl text-error mb-4" />
            <p className="text-text font-medium mb-2">{error}</p>
            <p className="text-text-light">Please run the database setup script first</p>
            <button
              onClick={refresh}
              className="mt-4 px-4 py-2 bg-primary text-white rounded-lg hover:bg-primary-dark"
            >
              Retry
            </button>
          </div>
        </div>
      </div>
    )
  }

  return (
    <div className="space-y-6">
      <Header 
        title="Alerts & Monitoring" 
        subtitle="Monitor system alerts, route submissions, and user activities"
      />

      <div className="grid grid-cols-1 lg:grid-cols-4 gap-6">
        <div className="lg:col-span-3 space-y-6">
          <div className="bg-white rounded-lg shadow p-6">
            <div className="flex items-center justify-between mb-6">
              <div className="flex items-center space-x-4">
                <select
                  value={filter}
                  onChange={(e) => setFilter(e.target.value)}
                  className="px-4 py-2 border border-border rounded-lg focus:outline-none focus:ring-2 focus:ring-primary"
                >
                  <option value="all">All Alerts</option>
                  <option value="unread">Unread</option>
                  <option value="read">Read</option>
                  <option value="new_route">New Routes</option>
                  <option value="payment">Payments</option>
                  <option value="system">System</option>
                </select>
              </div>

              <div className="flex items-center space-x-3">
                <button
                  onClick={handleCheckNewRoutes}
                  className="flex items-center space-x-2 px-4 py-2 border border-border rounded-lg hover:bg-gray-50"
                >
                  <FiRefreshCw />
                  <span>Check New Routes</span>
                </button>
                
                <button
                  onClick={refresh}
                  className="flex items-center space-x-2 px-4 py-2 bg-primary text-white rounded-lg hover:bg-primary-dark"
                >
                  <FiAlertCircle />
                  <span>Refresh</span>
                </button>
              </div>
            </div>

            <div className="space-y-4">
              {filteredAlerts.length === 0 ? (
                <div className="text-center py-12">
                  <FiCheckCircle className="text-success mx-auto text-4xl mb-4" />
                  <p className="text-text">No alerts found</p>
                  <p className="text-text-light">All systems are running smoothly</p>
                </div>
              ) : (
                filteredAlerts.map(alert => (
                  <div
                    key={alert.id}
                    className={`border rounded-lg p-4 ${alert.read ? 'bg-gray-50' : 'bg-white'}`}
                  >
                    <div className="flex items-start justify-between">
                      <div className="flex items-start">
                        <div className={`p-2 rounded-lg ${getSeverityColor(alert.severity)} mr-4`}>
                          {getTypeIcon(alert.type)}
                        </div>
                        <div>
                          <div className="flex items-center space-x-3">
                            <h4 className="font-semibold text-text">{alert.title}</h4>
                            <span className={`text-xs px-2 py-1 rounded-full ${getSeverityColor(alert.severity)}`}>
                              {alert.severity.toUpperCase()}
                            </span>
                            {alert.read && (
                              <span className="text-xs px-2 py-1 bg-success/10 text-success rounded-full">
                                READ
                              </span>
                            )}
                          </div>
                          <p className="text-text-light mt-1">{alert.message}</p>
                          <div className="flex items-center space-x-4 mt-2">
                            <span className="text-xs text-text-light flex items-center">
                              <FiClock className="mr-1" />
                              {new Date(alert.created_at).toLocaleString()}
                            </span>
                            <span className="text-xs text-text-light capitalize">
                              {alert.type.replace('_', ' ')}
                            </span>
                          </div>
                        </div>
                      </div>
                      
                      <div className="flex items-center space-x-2">
                        {!alert.read && (
                          <button
                            onClick={() => markAsRead(alert.id)}
                            className="px-3 py-1 bg-success text-white rounded-lg hover:bg-success/90 text-sm"
                          >
                            Mark Read
                          </button>
                        )}
                        <button
                          onClick={() => {
                            if (confirm('Delete this alert?')) {
                              deleteAlert(alert.id)
                            }
                          }}
                          className="px-3 py-1 bg-error text-white rounded-lg hover:bg-error/90 text-sm"
                        >
                          Delete
                        </button>
                      </div>
                    </div>
                    
                    {alert.data && Object.keys(alert.data).length > 0 && (
                      <div className="mt-3 ml-12">
                        <details className="text-sm">
                          <summary className="cursor-pointer text-primary hover:text-primary-dark">
                            View Details
                          </summary>
                          <pre className="mt-2 p-3 bg-gray-50 rounded text-xs overflow-x-auto">
                            {JSON.stringify(alert.data, null, 2)}
                          </pre>
                        </details>
                      </div>
                    )}
                  </div>
                ))
              )}
            </div>
          </div>
        </div>

        <div className="space-y-6">
          <div className="bg-white p-6 rounded-lg shadow">
            <h3 className="text-lg font-semibold text-text mb-4">Alert Statistics</h3>
            <div className="space-y-4">
              <div>
                <p className="text-text-light">Total Alerts</p>
                <p className="text-2xl font-bold text-text">{alerts.length}</p>
              </div>
              <div>
                <p className="text-text-light">Unread</p>
                <p className="text-2xl font-bold text-primary">
                  {alerts.filter(a => !a.read).length}
                </p>
              </div>
              <div>
                <p className="text-text-light">New Routes Today</p>
                <p className="text-2xl font-bold text-success">
                  {alerts.filter(a => 
                    a.type === 'new_route' && 
                    new Date(a.created_at).toDateString() === new Date().toDateString()
                  ).length}
                </p>
              </div>
            </div>
          </div>
        </div>
      </div>
    </div>
  )
}